class Solution:
    def levelOrder(self, root):
        if root is None:
            return []
        levels = []
        def visit(node, depth):
            if depth == len(levels):
                levels.append([])
            levels[depth].append(node.val)
            for child in (node.children or []):
                visit(child, depth + 1)
        visit(root, 0)
        return levels

