class Solution:
    def levelOrder(self, root):
        if root is None:
            return []
        result = []
        frontier = [root]
        while frontier:
            result.append([node.val for node in frontier])
            next_frontier = []
            for node in frontier:
                next_frontier.extend(node.children or [])
            frontier = next_frontier
        return result

