var levelOrder = function(root) {
    if (!root) return [];
    const result = [];
    let frontier = [root];
    while (frontier.length) {
        result.push(frontier.map(node => node.val));
        const next = [];
        for (const node of frontier) {
            for (const child of (node.children || [])) next.push(child);
        }
        frontier = next;
    }
    return result;
};
